mapper.select:
SELECT DATE_FORMAT(p.update_time, '%Y-%m-%d') AS date, COUNT(*) AS count FROM biz_user_progress p WHERE p.update_time >= #{startDate}
AND p.user_id = #{userId}
GROUP BY DATE_FORMAT(p.update_time, '%Y-%m-%d') ORDER BY date ASC

SELECT s.subject_id AS subjectId, s.subject_name AS subjectName, m.major_name AS majorName, COUNT(DISTINCT c.card_id) AS totalCards, SUM(CASE WHEN p.status IS NULL OR p.status = 0 THEN 1 ELSE 0 END) AS unlearnedCount, SUM(CASE WHEN p.status = 1 THEN 1 ELSE 0 END) AS fuzzyCount, SUM(CASE WHEN p.status = 2 THEN 1 ELSE 0 END) AS masteredCount FROM biz_subject s LEFT JOIN biz_major m ON s.major_id = m.major_id LEFT JOIN biz_card c ON c.subject_id = s.subject_id AND c.del_flag = '0' LEFT JOIN biz_user_progress p ON c.card_id = p.card_id
AND p.user_id = #{userId}
GROUP BY s.subject_id, s.subject_name, m.major_name HAVING totalCards > 0 ORDER BY m.major_name, s.subject_name

SELECT * FROM biz_user_progress
WHERE user_id = #{userId} AND card_id = #{cardId}
LIMIT 1

SELECT COUNT(*) FROM biz_user_progress


        AND user_id = #{userId}


        AND status  >=  #{minStatus}


        AND status  <=  #{maxStatus}


        AND update_time  >=  #{startTime}


        AND update_time  <  #{endTime}
